async function fetchUser(id) {
  try {
    const response = await fetch(`/api/users/${id}`);
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }
    const user = await response.json();
    return user;
  } catch (err) {
    // Catches both network failures and the throw above
    console.error('Failed to fetch user:', err.message);
    throw err; // re-throw so the caller knows it failed
  }
}

async function loadDashboard(userId) {
  let user;
  try {
    user = await fetchUser(userId);
  } catch (err) {
    // Can't proceed without the user — bail out
    return { error: 'User not found' };
  }

  let posts;
  try {
    posts = await fetchPosts(userId);
  } catch (err) {
    // Posts are optional — show empty list instead
    posts = [];
  }

  return { user, posts };
}

async function getToken() {
  const res = await fetch('/auth/token');
  if (!res.ok) throw new Error('Auth failed');
  return res.json();
}

async function fetchSecureData() {
  // If getToken() rejects, the throw surfaces here
  const { token } = await getToken();
  const res = await fetch('/api/data', {
    headers: { Authorization: `Bearer ${token}` },
  });
  return res.json();
}

async function loadPage() {
  try {
    const data = await fetchSecureData();
    renderPage(data);
  } catch (err) {
    // Catches failures from either getToken or fetchSecureData
    showError(err.message);
  }
}

class NetworkError extends Error {
  constructor(message, status) {
    super(message);
    this.name = 'NetworkError';
    this.status = status;
  }
}

class ValidationError extends Error {
  constructor(message, field) {
    super(message);
    this.name = 'ValidationError';
    this.field = field;
  }
}

async function submitForm(data) {
  try {
    const res = await fetch('/api/submit', {
      method: 'POST',
      body: JSON.stringify(data),
    });
    if (res.status === 422) {
      const body = await res.json();
      throw new ValidationError(body.message, body.field);
    }
    if (!res.ok) {
      throw new NetworkError(`Request failed`, res.status);
    }
    return res.json();
  } catch (err) {
    if (err instanceof ValidationError) {
      highlightField(err.field, err.message);
    } else if (err instanceof NetworkError) {
      showBanner(`Network error ${err.status}. Try again.`);
    } else {
      throw err; // unexpected — re-throw
    }
  }
}

// Called from a synchronous event listener — can't use await here
button.addEventListener('click', () => {
  submitForm(formData).catch((err) => {
    console.error('Unhandled submission error:', err);
  });
});

// Equivalent Promise chain style
fetchUser(id)
  .then((user) => renderProfile(user))
