async function loadWidgets(ids) {
  const results = await Promise.allSettled(
    ids.map((id) => fetchWidget(id))
  );

  const widgets = [];
  const errors = [];

  for (const result of results) {
    if (result.status === 'fulfilled') {
      widgets.push(result.value);
    } else {
      errors.push(result.reason);
    }
  }

  if (errors.length > 0) {
    console.warn(`${errors.length} widget(s) failed to load`);
  }

  return widgets;
}

// Browser
window.addEventListener('unhandledrejection', (event) => {
  console.error('Unhandled rejection:', event.reason);
  event.preventDefault(); // suppress console error
});

// Node.js
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled rejection at:', promise, 'reason:', reason);
  // In production: log to monitoring service, then optionally exit
});

// BUG: missing await — catch never runs on rejection
async function bad() {
  try {
    fetchUser(1); // no await!
  } catch (err) {
    // This catch block will NOT catch a rejection from fetchUser
    console.error(err);
  }
}

// CORRECT: await ensures rejection is caught
async function good() {
  try {
    await fetchUser(1);
  } catch (err) {
    console.error(err);
  }
}

// BAD: silent failure — error disappears, caller gets undefined
async function bad() {
  try {
    return await fetchUser(1);
  } catch (err) {}
}

// BETTER: at least log it
async function better() {
  try {
    return await fetchUser(1);
  } catch (err) {
    console.error('fetchUser failed:', err);
    return null; // explicit null signals failure to caller
  }
}

// BUG: errors in async forEach callbacks are unhandled rejections
ids.forEach(async (id) => {
  const user = await fetchUser(id); // rejection escapes!
  process(user);
});

// CORRECT: use for...of to stay inside async function scope
async function processAll(ids) {
  for (const id of ids) {
    try {
      const user = await fetchUser(id);
      process(user);
    } catch (err) {
      console.error(`Failed for id ${id}:`, err);
    }
  }
}

import { useState, useEffect } from 'react';

function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;

    async function load() {
      try {
        setLoading(true);
        const data = await fetchUser(userId);
        if (!cancelled) {
          setUser(data);
          setError(null);
        }
      } catch (err) {
        if (!cancelled) {
          setError(err.message);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    load();

    return () => {
      cancelled = true; // prevent stale state on unmount
    };
  }, [userId]);

  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error: {error}</p>;
  return <p>{user?.name}</p>;
}

// Returns [error, result] — inspired by Go-style error handling
async function to(promise) {
  try {
    const result = await promise;
    return [null, result];
  } catch (err) {
    return [err, null];
  }
}

// Usage
async function loadProfile(id) {
  const [userErr, user] = await to(fetchUser(id));
  if (userErr) {
    logError(userErr);
    return;
  }

  const [postsErr, posts] = await to(fetchPosts(id));
  if (postsErr) {
    return { user, posts: [] }; // degrade gracefully
  }

  return { user, posts };
}

async function saveDocument(doc) {
  setIsSaving(true); // start spinner
  try {
    await persistToServer(doc);
    showSuccessToast();
  } catch (err) {
    showErrorToast(err.message);
  } finally {
    setIsSaving(false); // always stop spinner
  }
}

// Wrap low-level error with application context
async function createOrder(cart) {
  try {
    return await api.post('/orders', cart);
  } catch (err) {
    // Turn opaque network error into domain error
    throw new Error(`Order creation failed: ${err.message}`, { cause: err });
  }
}
